import React, { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { taxasIRT } from '../data/mockData';
import { ConfiguracaoEmpresa } from '../types';

const Configuracoes: React.FC = () => {
  const { 
    empresa, setEmpresa, 
    isConfigured, setIsConfigured, 
    empresas, setEmpresas, 
    empresaId, setEmpresaId 
  } = useContext(AppContext);

  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('empresa');

  const emptyConfig: ConfiguracaoEmpresa = {
    id: Date.now(),
    nome: '',
    nif: '',
    endereco: '',
    municipio: '',
    provincia: '',
    telefone: '',
    email: '',
    banco: '',
    iban: '',
    taxaINSS: 3,
    taxaINSSPatronal: 8,
    taxaAGT: 2,
    processamentoAutomatico: false,
    envioAutomaticoContracheques: false,
    diaProcessamento: 5,
    regimeFiscal: 'Geral',
    tipoEntidade: 'Lda',
    categoria: 'Empresa'
  };

  const [config, setConfig] = useState<ConfiguracaoEmpresa>(empresa ? { ...empresa } : { ...emptyConfig });
  const [setupStep, setSetupStep] = useState(!empresa ? 'choice' : 'form');
  const [saved, setSaved] = useState(false);

  // Sincronizar quando a empresa mudar via switcher
  useEffect(() => {
    if (empresa) {
      setConfig({ ...empresa });
    }
  }, [empresa]);

  const handleChooseCategory = (category: 'Empresa' | 'Particular') => {
    setConfig({ ...emptyConfig, id: Date.now(), categoria: category });
    setSetupStep('form');
    setActiveTab('empresa');
  };

  const handleSave = () => {
    if (!config.nome || !config.nif) {
      alert('Por favor preencha pelo menos o Nome e o NIF.');
      return;
    }

    const empresaComId = { ...config, id: config.id || Date.now() };
    const idx = empresas.findIndex(e => e.id === empresaComId.id);

    let novasEmpresas = [...empresas];
    if (idx >= 0) {
      novasEmpresas[idx] = empresaComId;
    } else {
      novasEmpresas.push(empresaComId);
    }

    setEmpresas(novasEmpresas);
    setEmpresa(empresaComId);
    setEmpresaId(empresaComId.id);
    setIsConfigured(true);
    setSaved(true);

    setTimeout(() => {
      setSaved(false);
      if (!isConfigured) {
        navigate('/processamento');
      }
    }, 1500);
  };

  const handleSelectBusiness = (bus: any) => {
    setEmpresa(bus);
    setEmpresaId(bus.id);
    setConfig({ ...bus });
    setActiveTab('empresa');
    setSaved(true);
    setTimeout(() => setSaved(false), 1000);
  };

  const tabs = [
    { id: 'empresa', label: 'Dados Básicos', icon: 'business' },
    { id: 'impostos', label: 'Impostos/Taxas', icon: 'percent' },
    { id: 'processamento', label: 'Automações', icon: 'sync' },
    { id: 'gestao', label: 'Meus Negócios', icon: 'account_tree' },
  ];

  return (
    <div className="p-8 max-w-7xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
        <div>
          <nav className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">
            <span className="hover:text-primary cursor-pointer">Definições</span>
            <span className="material-symbols-outlined text-xs">chevron_right</span>
            <span className="text-slate-900 dark:text-white">Painel de Controlo</span>
          </nav>
          <h1 className="text-4xl font-black tracking-tight text-slate-900 dark:text-white uppercase">
            {setupStep === 'choice' ? 'Novo Cadastro' : 'Configurações'}
          </h1>
          <p className="text-slate-500 font-medium mt-1">
            {setupStep === 'choice' ? 'Adicione um novo negócio à sua conta.' : `Gestão activa: ${empresa?.nome || 'Configuração Pendente'}`}
          </p>
        </div>

        {setupStep !== 'choice' && (
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setSetupStep('choice')}
              className="px-5 py-3 rounded-xl border border-slate-200 dark:border-slate-800 text-xs font-black uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-800 transition-all flex items-center gap-2"
            >
              <span className="material-symbols-outlined text-lg">add</span>
              Novo Negócio
            </button>
            <button 
              onClick={handleSave} 
              className={`px-8 py-3 rounded-xl font-black uppercase tracking-widest text-xs transition-all flex items-center gap-2 shadow-xl ${saved ? 'bg-emerald-500 text-white' : 'bg-primary text-white hover:bg-primary/90 shadow-primary/20'}`}
            >
              {saved ? <><span className="material-symbols-outlined">check</span> Guardado</> : <><span className="material-symbols-outlined">save</span> Gravar Alterações</>}
            </button>
          </div>
        )}
      </div>

      {setupStep === 'choice' ? (
        <div className="max-w-4xl mx-auto mt-12 animate-in fade-in zoom-in-95 duration-500">
          <div className="text-center mb-12">
            <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter mb-4">Escolha o Tipo de Negócio</h2>
            <p className="text-slate-500 font-medium max-w-lg mx-auto uppercase text-xs tracking-wider">Pode gerenciar múltiplas empresas ou perfis particulares com a mesma conta.</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <button onClick={() => handleChooseCategory('Empresa')} className="bg-white dark:bg-slate-900 p-10 rounded-3xl border-2 border-slate-100 dark:border-slate-800 hover:border-primary transition-all group text-left shadow-2xl relative overflow-hidden">
               <div className="absolute -top-10 -right-10 size-40 bg-primary/5 rounded-full group-hover:scale-150 transition-transform duration-700"></div>
               <div className="size-16 rounded-2xl bg-primary/10 flex items-center justify-center text-primary mb-8 group-hover:rotate-12 transition-transform"><span className="material-symbols-outlined text-4xl">business</span></div>
               <h3 className="text-2xl font-black mb-3 uppercase tracking-tight text-slate-900 dark:text-white">Empresa / Lda / SA</h3>
               <p className="text-slate-500 text-sm leading-relaxed font-medium">Ideal para gestão empresarial completa, com regimes fiscais e segurança social patronal.</p>
            </button>

            <button onClick={() => handleChooseCategory('Particular')} className="bg-white dark:bg-slate-900 p-10 rounded-3xl border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-500 transition-all group text-left shadow-2xl relative overflow-hidden">
               <div className="absolute -top-10 -right-10 size-40 bg-indigo-500/5 rounded-full group-hover:scale-150 transition-transform duration-700"></div>
               <div className="size-16 rounded-2xl bg-indigo-500/10 flex items-center justify-center text-indigo-500 mb-8 group-hover:rotate-12 transition-transform"><span className="material-symbols-outlined text-4xl">home</span></div>
               <h3 className="text-2xl font-black mb-3 uppercase tracking-tight text-slate-900 dark:text-white">Particular / Doméstico</h3>
               <p className="text-slate-500 text-sm leading-relaxed font-medium">Para gestão de empregados domésticos ou prestadores individuais sem estrutura empresarial.</p>
            </button>
          </div>

          {empresas.length > 0 && (
            <div className="mt-12 text-center">
              <button onClick={() => setSetupStep('form')} className="text-[10px] font-black text-slate-400 uppercase tracking-[4px] hover:text-primary transition-colors">Voltar para a gestão</button>
            </div>
          )}
        </div>
      ) : (
        <div className="flex flex-col lg:flex-row gap-10">
          <aside className="lg:w-72 shrink-0">
            <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 p-3 shadow-sm sticky top-24">
              <nav className="space-y-1">
                {tabs.map(tab => (
                  <button 
                    key={tab.id} 
                    onClick={() => setActiveTab(tab.id)} 
                    className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === tab.id ? 'bg-primary text-white shadow-lg shadow-primary/20 font-black' : 'text-slate-500 dark:text-slate-400 font-bold hover:bg-slate-50 dark:hover:bg-slate-800'}`}
                  >
                    <span className="material-symbols-outlined text-[22px]">{tab.icon}</span>
                    <span className="text-[11px] uppercase tracking-widest">{tab.label}</span>
                  </button>
                ))}
              </nav>
            </div>
          </aside>

          <div className="flex-1 space-y-8 animate-in fade-in duration-500">
            {activeTab === 'empresa' && (
              <div className="space-y-8">
                <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm relative overflow-hidden">
                  <div className="flex items-center gap-4 mb-8">
                    <div className="size-10 rounded-xl bg-primary/10 flex items-center justify-center text-primary"><span className="material-symbols-outlined">badge</span></div>
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Identidade Jurídica</h3>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{config.categoria === 'Particular' ? 'Nome do Empregador' : 'Nome Comercial / Denominação'}</label>
                      <input type="text" value={config.nome} placeholder="Ex: Minha Empresa, Lda" onChange={(e) => setConfig({...config, nome: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold transition-all" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">NIF - Identificação Fiscal</label>
                      <input type="text" value={config.nif} placeholder="000000000" onChange={(e) => setConfig({...config, nif: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-black tracking-widest transition-all" />
                    </div>
                    {config.categoria === 'Empresa' && (
                      <>
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Regime Fiscal</label>
                          <select value={config.regimeFiscal} onChange={(e) => setConfig({...config, regimeFiscal: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold appearance-none cursor-pointer">
                            <option>Geral</option><option>Simplificado</option><option>Isento</option>
                          </select>
                        </div>
                        <div className="space-y-2">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Natureza Jurídica</label>
                          <select value={config.tipoEntidade} onChange={(e) => setConfig({...config, tipoEntidade: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold appearance-none cursor-pointer">
                            <option>Lda (Sociedade Limitada)</option><option>SA (Sociedade Anónima)</option><option>EI (Empresário Individual)</option><option>Sucursal / Outra</option>
                          </select>
                        </div>
                      </>
                    )}
                  </div>
                </section>

                <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm relative overflow-hidden">
                  <div className="flex items-center gap-4 mb-8">
                    <div className="size-10 rounded-xl bg-blue-500/10 flex items-center justify-center text-blue-500"><span className="material-symbols-outlined">map</span></div>
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Localização e Contacto</h3>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="md:col-span-2 space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Endereço Sede / Residencial</label>
                       <input type="text" value={config.endereco} onChange={(e) => setConfig({...config, endereco: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-medium" />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Telefone de Contacto</label>
                       <input type="text" value={config.telefone} onChange={(e) => setConfig({...config, telefone: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Email Oficial</label>
                       <input type="email" value={config.email} onChange={(e) => setConfig({...config, email: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                    </div>
                  </div>
                </section>

                <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm relative overflow-hidden text-slate-800 dark:text-white">
                    <div className="flex items-center gap-4 mb-8">
                      <div className="size-10 rounded-xl bg-emerald-500/10 flex items-center justify-center text-emerald-500"><span className="material-symbols-outlined">account_balance</span></div>
                      <h3 className="text-xl font-black uppercase tracking-tight">Dados Bancários / IBAN</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Instituição Bancária</label>
                        <input type="text" value={config.banco} placeholder="Ex: BFA, BAI, BPC" onChange={(e) => setConfig({...config, banco: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-bold" />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">IBAN Completo (AO06...)</label>
                        <input type="text" value={config.iban} placeholder="AO06 0000..." onChange={(e) => setConfig({...config, iban: e.target.value})} className="w-full px-5 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none focus:ring-2 focus:ring-primary font-black font-mono text-primary tracking-tight" />
                      </div>
                    </div>
                </section>
              </div>
            )}

            {activeTab === 'impostos' && (
              <div className="space-y-8 animate-in fade-in duration-500">
                <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
                  <div className="flex items-center gap-4 mb-8">
                    <div className="size-10 rounded-xl bg-amber-500/10 flex items-center justify-center text-amber-500"><span className="material-symbols-outlined">security_update_good</span></div>
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Segurança Social (INSS)</h3>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8 text-slate-900 dark:text-white">
                    <div className="bg-slate-50 dark:bg-slate-800/50 p-6 rounded-2xl space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Quota do Trabalhador (%)</label>
                      <div className="flex items-center gap-4">
                        <input type="number" step="0.5" value={config.taxaINSS} onChange={(e) => setConfig({...config, taxaINSS: Number(e.target.value)})} className="flex-1 bg-transparent text-3xl font-black outline-none border-b-2 border-slate-200 dark:border-slate-700 pb-2 focus:border-primary transition-colors" />
                        <span className="text-2xl font-black text-slate-300">%</span>
                      </div>
                    </div>
                    <div className="bg-slate-50 dark:bg-slate-800/50 p-6 rounded-2xl space-y-4">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Contribuição Patronal (%)</label>
                      <div className="flex items-center gap-4">
                        <input type="number" step="0.5" value={config.taxaINSSPatronal} onChange={(e) => setConfig({...config, taxaINSSPatronal: Number(e.target.value)})} className="flex-1 bg-transparent text-3xl font-black outline-none border-b-2 border-slate-200 dark:border-slate-700 pb-2 focus:border-primary transition-colors" />
                        <span className="text-2xl font-black text-slate-300">%</span>
                      </div>
                    </div>
                  </div>
                </section>

                <section className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
                  <div className="flex items-center gap-4 mb-8">
                    <div className="size-10 rounded-xl bg-rose-500/10 flex items-center justify-center text-rose-500"><span className="material-symbols-outlined">table_view</span></div>
                    <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Tabela Salarial de IRT</h3>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-left">
                      <thead>
                        <tr className="border-b border-slate-100 dark:border-slate-800 text-slate-900 dark:text-white">
                          <th className="pb-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Escalão de Rendimento</th>
                          <th className="pb-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Taxa Aplicada</th>
                          <th className="pb-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Parcela a Abater</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {taxasIRT.map(t => (
                          <tr key={t.id} className="group hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-all font-bold text-sm text-slate-900 dark:text-white">
                            <td className="py-4">De {t.minimo.toLocaleString()} até {t.maximo === 99999999 ? 'Infinito' : t.maximo.toLocaleString()} Kz</td>
                            <td className="py-4 group-hover:text-primary transition-colors">{t.taxa}%</td>
                            <td className="py-4 text-right">{t.parcelaAbt.toLocaleString()} Kz</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </section>
              </div>
            )}

            {activeTab === 'processamento' && (
              <div className="space-y-8 animate-in fade-in duration-500 text-slate-900 dark:text-white">
                <section className="bg-white dark:bg-slate-900 p-10 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
                  <div className="flex items-center gap-4 mb-10">
                    <div className="size-10 rounded-xl bg-indigo-500/10 flex items-center justify-center text-indigo-500"><span className="material-symbols-outlined">automation</span></div>
                    <h3 className="text-xl font-black uppercase tracking-tight">Motor de Cálculo</h3>
                  </div>

                  <div className="space-y-6">
                    <div className="flex items-center justify-between p-8 bg-slate-50 dark:bg-slate-800/80 rounded-[32px] border border-slate-100 dark:border-slate-700 transition-all hover:shadow-lg">
                      <div className="max-w-md">
                        <p className="font-black text-sm uppercase tracking-tight">Processamento Digital Automático</p>
                        <p className="text-xs text-slate-400 font-medium mt-2 leading-relaxed uppercase tracking-wider">O sistema fechará a folha de salários automaticamente no dia programado sem intervenção manual.</p>
                      </div>
                      <button onClick={() => setConfig({...config, processamentoAutomatico: !config.processamentoAutomatico})} className={`w-[72px] h-10 rounded-full transition-all flex items-center px-1.5 shadow-inner ${config.processamentoAutomatico ? 'bg-primary justify-end' : 'bg-slate-300 dark:bg-slate-700 justify-start'}`}>
                        <div className="size-7 bg-white rounded-full shadow-2xl transition-all duration-300"></div>
                      </button>
                    </div>

                    <div className="flex items-center justify-between p-8 bg-slate-50 dark:bg-slate-800/80 rounded-[32px] border border-slate-100 dark:border-slate-700 transition-all hover:shadow-lg">
                      <div>
                        <p className="font-black text-sm uppercase tracking-tight">Agendamento de Fecho (Dia Útil)</p>
                        <p className="text-xs text-slate-400 font-medium mt-2 uppercase tracking-wider">Defina o dia do mês limite para o cálculo.</p>
                      </div>
                      <div className="flex items-center gap-4 bg-white dark:bg-slate-900 p-3 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700">
                        <span className="text-[10px] font-black text-slate-300 uppercase">DIA</span>
                        <input type="number" min={1} max={28} value={config.diaProcessamento} onChange={(e) => setConfig({...config, diaProcessamento: Number(e.target.value)})} className="w-16 bg-transparent text-2xl font-black text-primary text-center outline-none" />
                      </div>
                    </div>
                  </div>
                </section>
              </div>
            )}

            {activeTab === 'gestao' && (
              <div className="space-y-8 animate-in slide-in-from-right-8 duration-500">
                <div className="flex items-center justify-between">
                  <h3 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Meus Negócios ({empresas.length})</h3>
                  <button onClick={() => setSetupStep('choice')} className="p-4 rounded-2xl bg-slate-900 dark:bg-white text-white dark:text-slate-900 text-[10px] font-black uppercase tracking-widest flex items-center gap-3 hover:scale-105 transition-all shadow-xl active:scale-95">
                    <span className="material-symbols-outlined text-sm">add_circle</span>
                    Cadastrar Empresa
                  </button>
                </div>

                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                  {empresas.map((bus) => (
                    <div 
                      key={bus.id} 
                      className={`group p-8 rounded-[32px] border-2 transition-all relative overflow-hidden cursor-pointer ${empresaId === bus.id ? 'border-primary bg-primary/[0.02] shadow-2xl ring-4 ring-primary/5' : 'border-slate-50 dark:border-slate-800 bg-white dark:bg-slate-900 hover:border-slate-200 hover:shadow-xl'}`}
                      onClick={() => handleSelectBusiness(bus)}
                    >
                       <div className={`absolute top-0 right-0 px-6 py-2 text-[9px] font-black uppercase tracking-[3px] rounded-bl-2xl transition-colors ${empresaId === bus.id ? 'bg-primary text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>
                         {empresaId === bus.id ? 'Seleccionada' : 'Disponível'}
                       </div>

                       <div className="flex items-center gap-6">
                          <div className={`size-20 rounded-[24px] flex items-center justify-center shadow-lg transition-transform group-hover:scale-110 duration-500 ${bus.categoria === 'Particular' ? 'bg-indigo-500 text-white' : 'bg-primary text-white'}`}>
                            <span className="material-symbols-outlined text-4xl">{bus.categoria === 'Particular' ? 'person' : 'business'}</span>
                          </div>
                          <div>
                            <h4 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tight line-clamp-1">{bus.nome || 'Sem Nome'}</h4>
                            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">NIF: {bus.nif || 'Não definido'}</p>
                            <div className="flex items-center gap-4 mt-4">
                               <div className="flex items-center gap-1.5 px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-[9px] font-black uppercase tracking-widest text-slate-500">
                                 <span className="material-symbols-outlined text-[10px]">location_on</span>
                                 {bus.provincia || 'S/ Local'}
                               </div>
                               <div className="flex items-center gap-1.5 px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-[9px] font-black uppercase tracking-widest text-slate-500">
                                 <span className="material-symbols-outlined text-[10px]">group</span>
                                 Multi-user
                               </div>
                            </div>
                          </div>
                       </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Configuracoes;
